    {
      "type": 9,
      "content": {
        "version": "KqlParameterItem/1.0",
        "parameters": [
          {
            "id": "param-timerange",
            "version": "KqlParameterItem/1.0",
            "name": "TimeRange",
            "label": "Time Range",
            "type": 4,
            "isRequired": true,
            "typeSettings": {
              "selectableValues": [
                {
                  "durationMs": 86400000
                },
                {
                  "durationMs": 604800000
                },
                {
                  "durationMs": 1209600000
                },
                {
                  "durationMs": 2592000000
                },
                {
                  "durationMs": 7776000000
                }
              ],
              "allowCustom": true
            },
            "value": {
              "durationMs": 2592000000
            }
          }
        ],
        "style": "pills",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces"
      },
      "name": "global-parameters"
    },
    {
      "type": 12,
      "name": "group-compliance",
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "Compliance"
      },
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "**ESS FRAGO-6 Compliance** — Compliant = last MDE check-in ≤ 30 days &nbsp;·&nbsp; Source: `DeviceInfo` (OnboardingStatus == 'Onboarded') &nbsp;·&nbsp; Follows Time Range selector",
              "style": "info"
            },
            "name": "text-compliance-header"
          },
          {
            "type": 3,
            "name": "compliance-chart",
            "content": {
              "version": "KqlItem/1.0",
                  "query": "let ComplianceData = DeviceInfo\n| where Timestamp {TimeRange}\n| where OnboardingStatus == 'Onboarded'\n| summarize LastSeen = max(Timestamp) by DeviceId, DeviceName\n| extend ComplianceStatus = iff(LastSeen >= ago(30d), 'Compliant', 'Noncompliant');\nComplianceData\n| summarize Count = count() by ComplianceStatus\n| extend SortOrder = case(ComplianceStatus == 'Compliant', 1, ComplianceStatus == 'Noncompliant', 2, 3)\n| order by SortOrder asc\n| project ComplianceStatus, Count",
              "size": 6,
              "title": "ESS FRAGO-6 Compliance Status - Last Communication within 1 Month",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
                  "visualization": "piechart"
            },
              "customWidth": "50"
          },
          {
            "type": 3,
            "name": "compliance-metrics",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nlet ComplianceData = DeviceInfo\n| where Timestamp {TimeRange}\n| where OnboardingStatus == 'Onboarded'\n| summarize LastSeen = max(Timestamp) by DeviceId, DeviceName\n| extend ComplianceStatus = iff(datetime_diff('day', CurrentTime, LastSeen) <= 30, 'Compliant', 'Noncompliant');\nlet TotalDevices = ComplianceData | summarize count();\nlet CompliantCount = ComplianceData | where ComplianceStatus == 'Compliant' | summarize count();\nComplianceData\n| summarize Total=count(), Compliant=countif(ComplianceStatus=='Compliant')\n| extend CompliancePercentage = round((Compliant * 100.0) / Total, 2)\n| project CompliancePercentage",
              "size": 9,
              "title": "Compliance Rate %",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "showBorder": true,
                "leftContent": {
                  "columnMatch": "CompliancePercentage",
                  "formatter": 12,
                  "formatOptions": {
                    "palette": "greenRed",
                    "showIcon": true
                  }
                }
              }
            },
                "customWidth": "50"
          },
          {
            "type": 3,
            "name": "compliance-trend",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nDeviceInfo\n| where Timestamp {TimeRange}\n| where OnboardingStatus == 'Onboarded'\n| summarize LastSeen = max(Timestamp) by DeviceId, DeviceName, Timestamp\n| extend DaysSinceLastSeen = datetime_diff('day', CurrentTime, LastSeen)\n| extend ComplianceStatus = iff(DaysSinceLastSeen <= 30, 'Compliant', 'Noncompliant')\n| summarize Compliant=countif(ComplianceStatus=='Compliant'), Noncompliant=countif(ComplianceStatus=='Noncompliant') by bin(Timestamp, 1d)\n| order by Timestamp asc",
              "size": 4,
              "title": "Compliance Trend - Green=Compliant | Red=Noncompliant",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "linechart",
              "chartSettings": {
                "showLegend": true,
                "seriesLabelSettings": [
                  {
                    "seriesName": "Compliant",
                    "color": "green"
                  },
                  {
                    "seriesName": "Noncompliant",
                    "color": "red"
                  }
                ]
              }
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "compliance-grid",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nDeviceInfo\n| where Timestamp {TimeRange}\n| where OnboardingStatus == 'Onboarded'\n| summarize LastSeen = max(Timestamp) by DeviceId, DeviceName\n| extend DaysSinceLastSeen = datetime_diff('day', CurrentTime, LastSeen)\n| extend ComplianceStatus = iff(DaysSinceLastSeen <= 30, 'Compliant', 'Noncompliant')\n| project DeviceName, DeviceId, LastSeen, DaysSinceLastSeen, ComplianceStatus\n| order by DaysSinceLastSeen asc",
              "size": 1,
              "title": "Compliance Details",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "showExportToExcel": true,
              "exportToExcelOptions": "visible",
              "gridSettings": {
                "filter": true,
                "rowLimit": 10000,
                "formatters": [
                  {
                    "columnMatch": "ComplianceStatus",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "icons",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Compliant", "representation": "success", "text": "{0}{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "2", "text": "{0}{1}" }
                      ]
                    }
                  },
                  {
                    "columnMatch": "DaysSinceLastSeen",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "<=", "thresholdValue": "30", "representation": "green", "text": "{0}d{1}" },
                        { "operator": "<=", "thresholdValue": "60", "representation": "yellow", "text": "{0}d{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "red", "text": "{0}d{1}" }
                      ]
                    }
                  }
                ]
              }
            },
            "customWidth": "100"
          }
        ]
      }
    },
    {
      "type": 12,
      "name": "group-edrsensor",
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "EDRSensor"
      },
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "**EDR Sensor Health** — Compliant = device last seen ≤ 7 days &nbsp;·&nbsp; Status panels use fixed 90-day window &nbsp;·&nbsp; Follows Time Range selector",
              "style": "info"
            },
            "name": "text-edrsensor-header"
          },
          {
            "type": 3,
            "name": "edrsensor-chart",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let InventoryWindow = 90d;\nlet SensorData = DeviceInfo\n| where Timestamp >= ago(InventoryWindow)\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState) by DeviceId\n| where OnboardingStatus == 'Onboarded'\n| extend SensorCommunicationStatus = iff(Timestamp >= ago(7d), 'Compliant', 'Noncompliant');\nSensorData\n| summarize Count = count() by SensorCommunicationStatus\n| extend SortOrder = case(SensorCommunicationStatus == 'Compliant', 1, SensorCommunicationStatus == 'Noncompliant', 2, 3)\n| order by SortOrder asc\n| project SensorCommunicationStatus, Count",
              "size": 6,
              "title": "EDR Sensor Status - Last Seen within 7 Days",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "piechart"
            },
            "customWidth": "50"
          },
          {
            "type": 3,
            "name": "edrsensor-metrics",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nlet InventoryWindow = 90d;\nlet SensorData = DeviceInfo\n| where Timestamp >= ago(InventoryWindow)\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState) by DeviceId\n| where OnboardingStatus == 'Onboarded'\n| extend LastSeen = Timestamp\n| extend DaysSinceLastSeen = datetime_diff('day', CurrentTime, LastSeen)\n| extend SensorCommunicationStatus = iff(DaysSinceLastSeen <= 7, 'Compliant', 'Noncompliant');\nSensorData\n| summarize Total=count(), Compliant=countif(SensorCommunicationStatus=='Compliant')\n| extend CompliancePercentage = round((Compliant * 100.0) / Total, 2)\n| project CompliancePercentage",
              "size": 9,
              "title": "EDR Sensor Compliance %",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "showBorder": true,
                "leftContent": {
                  "columnMatch": "CompliancePercentage",
                  "formatter": 12,
                  "formatOptions": {
                    "palette": "greenRed",
                    "showIcon": true
                  }
                }
              }
            },
            "customWidth": "50"
          },
          {
            "type": 3,
            "name": "edrsensor-trend",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nDeviceInfo\n| where Timestamp {TimeRange}\n| where OnboardingStatus == 'Onboarded'\n| summarize LastSeen = max(Timestamp) by DeviceId, DeviceName, Timestamp\n| extend DaysSinceLastSeen = datetime_diff('day', CurrentTime, LastSeen)\n| extend SensorCommunicationStatus = iff(DaysSinceLastSeen <= 7, 'Compliant', 'Noncompliant')\n| summarize Compliant=countif(SensorCommunicationStatus=='Compliant'), Noncompliant=countif(SensorCommunicationStatus=='Noncompliant') by bin(Timestamp, 1d)\n| order by Timestamp asc",
              "size": 4,
              "title": "EDR Sensor Trend - Green=Compliant | Red=Noncompliant",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "linechart",
              "chartSettings": {
                "showLegend": true,
                "seriesLabelSettings": [
                  {
                    "seriesName": "Compliant",
                    "color": "green"
                  },
                  {
                    "seriesName": "Noncompliant",
                    "color": "red"
                  }
                ]
              }
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "edrsensor-grid",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nlet InventoryWindow = 90d;\nDeviceInfo\n| where Timestamp >= ago(InventoryWindow)\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState, DeviceName) by DeviceId\n| where OnboardingStatus == 'Onboarded'\n| extend LastSeen = Timestamp\n| extend DaysSinceLastSeen = datetime_diff('day', CurrentTime, LastSeen)\n| extend SensorCommunicationStatus = iff(DaysSinceLastSeen <= 7, 'Compliant', 'Noncompliant')\n| project DeviceName, DeviceId, LastSeen, DaysSinceLastSeen, OnboardingStatus, SensorHealthState, SensorCommunicationStatus\n| order by DaysSinceLastSeen asc",
              "size": 2,
              "title": "EDR Sensor Details",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "showExportToExcel": true,
              "exportToExcelOptions": "visible",
              "gridSettings": {
                "filter": true,
                "rowLimit": 10000,
                "formatters": [
                  {
                    "columnMatch": "SensorCommunicationStatus",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "icons",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Compliant", "representation": "success", "text": "{0}{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "2", "text": "{0}{1}" }
                      ]
                    }
                  },
                  {
                    "columnMatch": "SensorHealthState",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "icons",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Active", "representation": "success", "text": "{0}{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "3", "text": "{0}{1}" }
                      ]
                    }
                  },
                  {
                    "columnMatch": "DaysSinceLastSeen",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "<=", "thresholdValue": "7", "representation": "green", "text": "{0}d{1}" },
                        { "operator": "<=", "thresholdValue": "14", "representation": "yellow", "text": "{0}d{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "red", "text": "{0}d{1}" }
                      ]
                    }
                  }
                ]
              }
            },
            "customWidth": "100"
          }
        ]
      }
    },
    {
      "type": 12,
      "name": "group-edrav",
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "EDRAV"
      },
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "**EDR / AV Installation Coverage** — EDR+AV Installed / AV Only / EDR Only / No Coverage &nbsp;·&nbsp; Sources: `DeviceInfo` · `DeviceProcessEvents` · `DeviceNetworkEvents` · `DeviceFileEvents` · `DeviceImageLoadEvents` · `DeviceRegistryEvents` &nbsp;·&nbsp; Follows Time Range selector",
              "style": "info"
            },
            "name": "text-edrav-header"
          },
          {
            "type": 3,
            "name": "edrav-chart",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let Devices = DeviceInfo\n| where Timestamp {TimeRange}\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState, JoinType, IsAzureADJoined) by DeviceId, DeviceName\n| extend EDRLastSeen = Timestamp\n| extend JoinClassification = case(tostring(JoinType) =~ 'AAD Joined' or IsAzureADJoined == 1, 'AAD Joined', isempty(tostring(JoinType)), 'Unknown/Not Reported', tostring(JoinType));\nlet AvTelemetry = union isfuzzy=true\n(DeviceProcessEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceNetworkEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceFileEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceImageLoadEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceRegistryEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp);\nlet AvInstalled = AvTelemetry\n| summarize AVLastSeen = max(Timestamp) by DeviceId;\nDevices\n| join kind=leftouter AvInstalled on DeviceId\n| extend HasEDR = OnboardingStatus == 'Onboarded' and SensorHealthState == 'Active'\n| extend HasAV = isnotnull(AVLastSeen)\n| extend InstallStatus = case(HasEDR and HasAV, 'EDR+AV Installed', HasEDR and not(HasAV), 'EDR Only (No AV)', not(HasEDR) and HasAV, 'AV Only (No EDR)', not(HasEDR) and not(HasAV), 'No EDR/No AV', 'Unknown')\n| extend ComplianceStatus = iff(InstallStatus == 'EDR+AV Installed', 'Compliant', 'Not Compliant')\n| extend SortOrder = case(InstallStatus == 'EDR+AV Installed', 1, InstallStatus == 'AV Only (No EDR)', 2, InstallStatus == 'EDR Only (No AV)', 3, InstallStatus == 'No EDR/No AV', 4, 5)\n| summarize NumberOfSystems = count() by InstallStatus, SortOrder\n| order by SortOrder asc\n| project InstallStatus, NumberOfSystems",
              "size": 2,
              "title": "EDR/AV Install Status - All Devices",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "categoricalbar",
              "chartSettings": {
                "showLegend": true,
                "seriesLabelSettings": [
                  {
                    "seriesName": "EDR+AV Installed",
                    "color": "green"
                  },
                  {
                    "seriesName": "AV Only (No EDR)",
                    "color": "#FFBF00"
                  },
                  {
                    "seriesName": "EDR Only (No AV)",
                    "color": "orange"
                  },
                  {
                    "seriesName": "No EDR/No AV",
                    "color": "red"
                  }
                ]
              }
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "edrav-trend",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let DeviceDaily = DeviceInfo\n| where Timestamp {TimeRange}\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState) by Day = bin(Timestamp, 1d), DeviceId, DeviceName;\nlet AvDaily = union isfuzzy=true\n(DeviceProcessEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Day = bin(Timestamp, 1d)),\n(DeviceNetworkEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Day = bin(Timestamp, 1d)),\n(DeviceFileEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Day = bin(Timestamp, 1d)),\n(DeviceImageLoadEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Day = bin(Timestamp, 1d)),\n(DeviceRegistryEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Day = bin(Timestamp, 1d))\n| summarize HasAVSignal = any(true) by DeviceId, Day;\nDeviceDaily\n| join kind=leftouter AvDaily on DeviceId, Day\n| extend HasEDR = OnboardingStatus == 'Onboarded' and SensorHealthState == 'Active'\n| extend HasAV = coalesce(HasAVSignal, false)\n| summarize ['EDR+AV Installed'] = countif(HasEDR and HasAV), ['AV Only (No EDR)'] = countif(not(HasEDR) and HasAV), ['EDR Only (No AV)'] = countif(HasEDR and not(HasAV)), ['No EDR/No AV'] = countif(not(HasEDR) and not(HasAV)) by Timestamp = Day\n| order by Timestamp asc",
              "size": 4,
              "title": "EDR/AV Install Trend",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "linechart",
              "chartSettings": {
                "showLegend": true,
                "seriesLabelSettings": [
                  {
                    "seriesName": "EDR+AV Installed",
                    "color": "green"
                  },
                  {
                    "seriesName": "AV Only (No EDR)",
                    "color": "#FFBF00"
                  },
                  {
                    "seriesName": "EDR Only (No AV)",
                    "color": "orange"
                  },
                  {
                    "seriesName": "No EDR/No AV",
                    "color": "red"
                  }
                ]
              }
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "edrav-grid",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let Devices = DeviceInfo\n| where Timestamp {TimeRange}\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState, JoinType, IsAzureADJoined) by DeviceId, DeviceName\n| extend EDRLastSeen = Timestamp\n| extend JoinClassification = case(tostring(JoinType) =~ 'AAD Joined' or IsAzureADJoined == 1, 'AAD Joined', isempty(tostring(JoinType)), 'Unknown/Not Reported', tostring(JoinType));\nlet AvTelemetry = union isfuzzy=true\n(DeviceProcessEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceNetworkEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceFileEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceImageLoadEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceRegistryEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp);\nlet AvInstalled = AvTelemetry\n| summarize AVLastSeen = max(Timestamp) by DeviceId;\nDevices\n| join kind=leftouter AvInstalled on DeviceId\n| extend HasEDR = OnboardingStatus == 'Onboarded' and SensorHealthState == 'Active'\n| extend HasAV = isnotnull(AVLastSeen)\n| extend InstallStatus = case(HasEDR and HasAV, 'EDR+AV Installed', HasEDR and not(HasAV), 'EDR Only (No AV)', not(HasEDR) and HasAV, 'AV Only (No EDR)', not(HasEDR) and not(HasAV), 'No EDR/No AV', 'Unknown')\n| extend ComplianceStatus = iff(InstallStatus == 'EDR+AV Installed', 'Compliant', 'Not Compliant')\n| extend SortOrder = case(InstallStatus == 'EDR+AV Installed', 1, InstallStatus == 'AV Only (No EDR)', 2, InstallStatus == 'EDR Only (No AV)', 3, InstallStatus == 'No EDR/No AV', 4, 5)\n| project DeviceName, DeviceId, EDRLastSeen, AVLastSeen, OnboardingStatus, SensorHealthState, InstallStatus, ComplianceStatus , SortOrder\n| order by SortOrder asc, DeviceName asc",
              "size": 2,
