        "items": [
          {
            "type": 1,
            "content": {
              "json": "**AV Sensor Health** — Compliant = `MsMpEng.exe` / `mdatp` / `wdavdaemon` / `wdavdaemonapp` active ≤ 7 days &nbsp;·&nbsp; Status panels use fixed 90-day window &nbsp;·&nbsp; Linux: uses `DeviceInfo` heartbeat as fallback &nbsp;·&nbsp; Follows Time Range selector",
              "style": "info"
            },
            "name": "text-avsensor-header"
          },
          {
            "type": 3,
            "name": "avsensor-chart",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nlet InventoryWindow = 90d;\nlet SignalWindow = 7d;\nlet OnboardedDevices = DeviceInfo\n| where Timestamp >= ago(InventoryWindow)\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState) by DeviceId, DeviceName\n| where OnboardingStatus == 'Onboarded'\n| project DeviceId, DeviceName;\nlet MdavTelemetry = union isfuzzy=true\n(DeviceProcessEvents\n| where Timestamp >= ago(SignalWindow)\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceNetworkEvents\n| where Timestamp >= ago(SignalWindow)\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceFileEvents\n| where Timestamp >= ago(SignalWindow)\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceImageLoadEvents\n| where Timestamp >= ago(SignalWindow)\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceRegistryEvents\n| where Timestamp >= ago(SignalWindow)\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp);\nlet MdavLastSeen = MdavTelemetry\n| summarize LastSeen = max(Timestamp) by DeviceId;\nOnboardedDevices\n| join kind=leftouter MdavLastSeen on DeviceId\n| extend DaysSinceLastSeen = iif(isnull(LastSeen), int(null), datetime_diff('day', CurrentTime, LastSeen))\n| extend AVCommunicationStatus = iff(isnotnull(LastSeen) and DaysSinceLastSeen <= 7, 'Compliant', 'Noncompliant')\n| summarize Count = count() by AVCommunicationStatus\n| extend SortOrder = case(AVCommunicationStatus == 'Compliant', 1, AVCommunicationStatus == 'Noncompliant', 2, 3)\n| order by SortOrder asc\n| project AVCommunicationStatus, Count",
              "size": 6,
              "title": "AV Sensor Status - Defender AV Process Seen within 7 Days",
