          {
            "type": 3,
            "name": "avsensor-trend",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let OnboardedDevices = DeviceInfo\n| where Timestamp {TimeRange}\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState) by DeviceId, DeviceName\n| where OnboardingStatus == 'Onboarded'\n| project DeviceId, DeviceName;\nlet TotalOnboarded = toscalar(OnboardedDevices | count);\nlet DayBounds = DeviceInfo\n| where Timestamp {TimeRange}\n| summarize StartDay = startofday(min(Timestamp)), EndDay = startofday(max(Timestamp));\nlet MdavDailySeen = union isfuzzy=true\n(DeviceProcessEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, SeenDay = startofday(Timestamp)),\n(DeviceNetworkEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, SeenDay = startofday(Timestamp)),\n(DeviceFileEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, SeenDay = startofday(Timestamp)),\n(DeviceImageLoadEvents\n| where Timestamp {TimeRange}\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, SeenDay = startofday(Timestamp)),\n(DeviceRegistryEvents\n| where Timestamp {TimeRange}\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, SeenDay = startofday(Timestamp))\n| where DeviceId in (OnboardedDevices | project DeviceId)\n| summarize by DeviceId, SeenDay;\nrange Day from toscalar(DayBounds | project StartDay) to toscalar(DayBounds | project EndDay) step 1d\n| extend JoinKey = 1\n| join kind=leftouter (MdavDailySeen | extend JoinKey = 1) on JoinKey\n| summarize Compliant = dcountif(DeviceId, SeenDay between (Day - 6d .. Day)) by Day\n| extend Noncompliant = TotalOnboarded - Compliant\n| project Timestamp = Day, Compliant, Noncompliant\n| order by Timestamp asc",
              "size": 4,
