            "content": {
              "version": "KqlItem/1.0",
              "query": "let CurrentTime = now();\nlet InventoryWindow = 90d;\nlet SignalWindow = 7d;\nlet OnboardedDevices = DeviceInfo\n| where Timestamp >= ago(InventoryWindow)\n| summarize arg_max(Timestamp, OnboardingStatus, SensorHealthState, OSPlatform) by DeviceId, DeviceName\n| where OnboardingStatus == 'Onboarded'\n| project DeviceId, DeviceName, OnboardingStatus, SensorHealthState, OSPlatform, DeviceInfoLastSeen = Timestamp;\nlet MdavTelemetry = union isfuzzy=true\n(DeviceProcessEvents\n| where Timestamp >= ago(SignalWindow)\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceNetworkEvents\n| where Timestamp >= ago(SignalWindow)\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceFileEvents\n| where Timestamp >= ago(SignalWindow)\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceImageLoadEvents\n| where Timestamp >= ago(SignalWindow)\n| where FileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp') or InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp),\n(DeviceRegistryEvents\n| where Timestamp >= ago(SignalWindow)\n| where InitiatingProcessFileName in~ ('MsMpEng.exe', 'mdatp', 'wdavdaemon', 'wdavdaemonapp')\n| project DeviceId, Timestamp);\nlet MdavLastSeen = MdavTelemetry\n| summarize LastSeen = max(Timestamp) by DeviceId;\nOnboardedDevices\n| join kind=leftouter MdavLastSeen on DeviceId\n| extend EffectiveLastSeen = iif(isnull(LastSeen) and OSPlatform has 'Linux', DeviceInfoLastSeen, LastSeen)\n| extend DaysSinceLastSeen = iif(isnull(EffectiveLastSeen), int(null), datetime_diff('day', CurrentTime, EffectiveLastSeen))\n| extend AVCommunicationStatus = iff(isnotnull(EffectiveLastSeen) and DaysSinceLastSeen <= 7, 'Compliant', 'Noncompliant')\n| project DeviceName, DeviceId, OSPlatform, LastSeen = EffectiveLastSeen, DaysSinceLastSeen, OnboardingStatus, SensorHealthState, AVCommunicationStatus\n| order by isnull(LastSeen) asc, DaysSinceLastSeen asc",
              "size": 2,
