            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceNetworkEvents\n| where Timestamp {TimeRange}\n| extend ActionTypeLc = tolower(ActionType)\n| extend FirewallEventLabel = case(ActionTypeLc has_any ('blocked','denied','drop','reject'), 'Blocked', ActionTypeLc has_any ('allowed','success'), 'Allowed', ActionType in~ ('ConnectionFailed','ConnectionFailedAggregatedReport'), 'Failed Connection', ActionType has_any ('ConnectionAcknowledged','ConnectionSuccess','DnsConnectionInspected','SslConnectionInspected'), 'Connection Activity', '')\n| where FirewallEventLabel != ''\n| summarize ['Number of Firewall Events']=count() by ['Event Generated Time']=bin(Timestamp, 1d), ['Firewall Event Label']=FirewallEventLabel\n| order by ['Event Generated Time'] asc",
              "size": 2,
              "title": "MDE Firewall Signals by Classification",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "linechart"
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "fw-grid",
            "content": {
              "version": "KqlItem/1.0",
              "query": "DeviceNetworkEvents\n| where Timestamp {TimeRange}\n| extend ActionTypeLc = tolower(ActionType)\n| extend FirewallEventLabel = case(ActionTypeLc has_any ('blocked','denied','drop','reject'), 'Blocked', ActionTypeLc has_any ('allowed','success'), 'Allowed', ActionType in~ ('ConnectionFailed','ConnectionFailedAggregatedReport'), 'Failed Connection', ActionType has_any ('ConnectionAcknowledged','ConnectionSuccess','DnsConnectionInspected','SslConnectionInspected'), 'Connection Activity', '')\n| where FirewallEventLabel != ''\n| extend SortOrder = case(FirewallEventLabel == 'Blocked', 1, FirewallEventLabel == 'Allowed', 2, FirewallEventLabel == 'Connection Activity', 3, FirewallEventLabel == 'Failed Connection', 4, 5)\n| summarize ['Event Count']=count(), ['Unique Remote IPs']=dcountif(RemoteIP, isnotempty(RemoteIP)), ['Unique Destination Ports']=dcountif(RemotePort, isnotnull(RemotePort)), ['Protocols Seen']=make_set(Protocol, 4), ['Action Types Seen']=make_set(ActionType, 5) by ['Firewall Event Label']=FirewallEventLabel, SortOrder, DeviceName\n| order by SortOrder asc, ['Event Count'] desc\n| project-away SortOrder",
              "size": 2,
