        "items": [
          {
            "type": 1,
            "content": {
              "json": "**Threat Events** — Sentinel incidents and alerts &nbsp;·&nbsp; Tiles: Total Incidents · Total Alerts · Open Incidents · High Severity &nbsp;·&nbsp; Source: `SecurityIncident` · Follows Time Range selector",
              "style": "info"
