          {
            "type": 3,
            "name": "threat-tiles",
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityIncident\n| where TimeGenerated {TimeRange}\n| extend AlertsData = parse_json(AdditionalData)\n| extend AlertCount = toint(AlertsData.alertsCount)\n| summarize TotalIncidents=count(), TotalAlerts=sum(AlertCount), OpenIncidents=countif(Status != 'Closed'), HighSeverity=countif(Severity == 'High')\n| extend r = pack_array(pack('label','Total Incidents','value',TotalIncidents), pack('label','Total Alerts','value',TotalAlerts), pack('label','Open Incidents','value',OpenIncidents), pack('label','High Severity','value',HighSeverity))\n| mv-expand r\n| project label=tostring(r.label), value=toint(r.value)",
