              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "showBorder": false,
                "titleContent": {
                  "columnMatch": "label"
                },
                "leftContent": {
                  "columnMatch": "value",
                  "formatter": 12,
