            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "threat-piechart",
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityIncident\n| where TimeGenerated {TimeRange}\n| extend AD = parse_json(AdditionalData)\n| extend Sources = parse_json(tostring(AD.alertProductNames))\n| mv-expand Source = Sources\n| extend SourceName = tostring(Source)\n| where isnotempty(SourceName)\n| summarize Count=count() by SourceName\n| order by Count desc",
