            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityIncident\n| where TimeGenerated {TimeRange}\n| extend AlertsData = parse_json(AdditionalData)\n| extend AlertCount = toint(AlertsData.alertsCount)\n| summarize IncidentCount = count(), TotalAlerts = sum(AlertCount) by IncidentName = Title\n| top 5 by IncidentCount desc\n| extend IncidentLabel = iff(strlen(IncidentName) > 24, strcat(substring(IncidentName, 0, 24), '...'), IncidentName)\n| project IncidentLabel, IncidentCount, TotalAlerts\n| order by IncidentCount desc",
              "size": 0,
              "title": "Threat Events - Top 5 Incidents by Count",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "categoricalbar",
              "chartSettings": {
                "xAxis": "IncidentLabel",
                "seriesLabelSettings": [
                  {
                    "seriesName": "IncidentCount",
                    "color": "blue"
                  },
                  {
                    "seriesName": "TotalAlerts",
                    "color": "orange"
                  }
                ]
              }
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "threat-grid",
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityIncident\n| where TimeGenerated {TimeRange}\n| extend AlertsData = parse_json(AdditionalData)\n| extend AlertCount = toint(AlertsData.alertsCount)\n| extend IncidentStatus = tostring(column_ifexists('Status', ''))\n| extend IncidentSeverity = tostring(column_ifexists('Severity', ''))\n| summarize ['Incident Count']=count(), ['Total Alerts']=sum(AlertCount), ['Open Incidents']=countif(IncidentStatus != 'Closed'), ['High Severity Incidents']=countif(IncidentSeverity == 'High') by ['Incident Name']=Title\n| order by ['Incident Count'] desc",
              "size": 2,
              "title": "Threat Event Details",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "showExportToExcel": true,
              "exportToExcelOptions": "visible",
              "gridSettings": {
                "filter": true,
                "rowLimit": 10000,
                "formatters": [
                  {
                    "columnMatch": "Open Incidents",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "0", "representation": "green", "text": "{0}{1}" },
                        { "operator": ">", "thresholdValue": "0", "representation": "red", "text": "{0}{1}" },
