                        { "operator": "==", "thresholdValue": "0", "representation": "green", "text": "{0}{1}" },
                        { "operator": ">", "thresholdValue": "0", "representation": "redBright", "text": "{0}{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "yellow", "text": "{0}{1}" }
                      ]
