    {
      "type": 12,
      "name": "group-dlpevents",
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "DLPEvents"
      },
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "**DLP Events — USB / Removable Media** — USB Mass Storage connections · file writes within 900s of connection &nbsp;·&nbsp; Sources: `DeviceEvents` · `DeviceFileEvents` · Follows Time Range selector",
              "style": "info"
            },
            "name": "text-dlp-header"
          },
          {
            "type": 3,
            "name": "dlpevents-linechart",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let DlpBase = SecurityAlert\n| where TimeGenerated {TimeRange}\n| where DisplayName contains 'USB'\n| extend ApprovalStatus = iff(Status == 'New', 'Not Approved', 'Approved');\nlet SpanDays = toscalar(DlpBase | summarize spanDays = todouble(datetime_diff('day', max(TimeGenerated), min(TimeGenerated))));\nlet BinSize = case(\n    isnull(SpanDays), 1d,\n    SpanDays <= 31, 1d,\n    SpanDays <= 120, 2d,\n    SpanDays <= 365, 7d,\n    SpanDays <= 730, 14d,\n    30d\n);\nDlpBase\n| summarize IncidentCount = count() by ['Last Update'] = bin(TimeGenerated, BinSize), ApprovalStatus\n| order by ['Last Update'] asc",
              "size": 1,
              "title": "Weekly DLP: Number of USB Incidents per day (approved/not approved)",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "linechart",
              "chartSettings": {
                "xAxis": "Last Update",
                "yAxis": ["IncidentCount"],
                "ySettings": {
                  "numberFormatSettings": {
                    "unit": 17,
                    "options": {
                      "style": "decimal",
                      "maximumFractionDigits": 0
                    }
                  }
                },
                "seriesLabelSettings": [
                  {
                    "seriesName": "Approved",
                    "label": "Approved USB Devices",
                    "color": "green"
                  },
                  {
                    "seriesName": "Not Approved",
                    "label": "Unapproved USB Devices",
                    "color": "red"
                  }
                ]
              }
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "dlpevents-grid",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let DeviceNameToSearch = '';\nlet TimespanInSeconds = 900;\nlet Connections =\nDeviceEvents\n| where Timestamp {TimeRange}\n| where (isempty(DeviceNameToSearch) or DeviceName =~ DeviceNameToSearch) and ActionType == 'PnpDeviceConnected'\n| extend parsed = parse_json(AdditionalFields)\n| project DeviceId, DeviceName, ConnectionTime = Timestamp, DeviceClass = tostring(parsed.ClassName), UsbDeviceId = tostring(parsed.DeviceId), ClassId = tostring(parsed.DeviceId), DeviceDescription = tostring(parsed.DeviceDescription), VendorIds = tostring(parsed.VendorIds)\n| where DeviceClass == 'USB' and DeviceDescription == 'USB Mass Storage Device';\nDeviceFileEvents\n| where Timestamp {TimeRange}\n| where (isempty(DeviceNameToSearch) or DeviceName =~ DeviceNameToSearch) and FolderPath !startswith 'c' and FolderPath !startswith @'\\'\n| join kind=inner Connections on DeviceId\n| where datetime_diff('second', Timestamp, ConnectionTime) <= TimespanInSeconds\n| top 250 by Timestamp desc\n| project ['Last Update']=Timestamp, DeviceName, InitiatingProcessAccountName, DeviceClass, DeviceDescription, FileName",
              "size": 2,
              "title": "DLP Event Details (USB Enriched)",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "showExportToExcel": true,
              "exportToExcelOptions": "visible",
              "gridSettings": {
                "filter": true,
                "rowLimit": 100000
              }
            },
            "customWidth": "100"
          }
        ]
      }
    },
    {
      "type": 12,
      "name": "group-intunefw",
      "conditionalVisibility": {
        "parameterName": "Tab",
        "comparison": "isEqualTo",
        "value": "IntuneFireWall"
      },
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "**FW Policy Compliance** — Scoped to FW Policy · Uses downstream sync and compliance activity as evidence &nbsp;·&nbsp; Sources: `IntuneAuditLogs` · `IntuneDeviceComplianceOrg` &nbsp;·&nbsp; Follows Time Range selector",
              "style": "info"
            },
            "name": "text-intunefw-header"
          },
          {
            "type": 3,
            "name": "intunefw-chart",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let FWPolicyName = 'FW Policy';\nlet LatestAssignmentTime = toscalar(\n    IntuneAuditLogs\n    | where TimeGenerated {TimeRange}\n    | extend P = parse_json(Properties)\n    | extend PolicyName = tostring(coalesce(P.TargetDisplayNames[0], P.Targets[0].Name, ''))\n    | where PolicyName =~ FWPolicyName\n    | where OperationName has 'DeviceManagementConfigurationPolicyAssignment'\n    | where ResultType == 'Success'\n    | summarize LatestAssignment=max(TimeGenerated)\n);\nlet DevicesSynced = toscalar(\n    IntuneAuditLogs\n    | where isnotnull(LatestAssignmentTime)\n    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)\n    | where OperationName == 'syncDevice ManagedDevice'\n    | extend ManagedDeviceId = tostring(extractjson('$.TargetObjectIds[0]', Properties))\n    | where isnotempty(ManagedDeviceId)\n    | summarize dcount(ManagedDeviceId)\n);\nlet DevicesCompliance = toscalar(\n    IntuneDeviceComplianceOrg\n    | where isnotnull(LatestAssignmentTime)\n    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)\n    | where OperationName == 'DeviceCompliance'\n    | where isnotempty(DeviceId)\n    | summarize dcount(DeviceId)\n);\nunion\n(print Evidence='Successful FW Policy Assignments', Count=iff(isnull(LatestAssignmentTime), 0, 1)),\n(print Evidence='Devices Synced in 24h', Count=coalesce(DevicesSynced, 0)),\n(print Evidence='Devices with Compliance Check in 24h', Count=coalesce(DevicesCompliance, 0))",
              "size": 6,
              "title": "Latest FW Policy Evidence Snapshot",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "categoricalbar",
              "chartSettings": {
                "showLegend": true,
                "seriesLabelSettings": [
                  {
                    "seriesName": "Successful FW Policy Assignments",
                    "color": "green"
                  },
                  {
                    "seriesName": "Devices Synced in 24h",
                    "color": "blue"
                  },
                  {
                    "seriesName": "Devices with Compliance Check in 24h",
                    "color": "orange"
                  }
                ]
              }
            },
            "customWidth": "60"
          },
          {
            "type": 3,
            "name": "intunefw-metrics",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let FWPolicyName = 'FW Policy';\nlet LatestAssignmentTime = toscalar(\n    IntuneAuditLogs\n    | where TimeGenerated {TimeRange}\n    | extend P = parse_json(Properties)\n    | extend PolicyName = tostring(coalesce(P.TargetDisplayNames[0], P.Targets[0].Name, ''))\n    | where PolicyName =~ FWPolicyName\n    | where OperationName has 'DeviceManagementConfigurationPolicyAssignment'\n    | where ResultType == 'Success'\n    | summarize LatestAssignment=max(TimeGenerated)\n);\nlet DevicesSynced = toscalar(\n    IntuneAuditLogs\n    | where isnotnull(LatestAssignmentTime)\n    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)\n    | where OperationName == 'syncDevice ManagedDevice'\n    | extend ManagedDeviceId = tostring(extractjson('$.TargetObjectIds[0]', Properties))\n    | where isnotempty(ManagedDeviceId)\n    | summarize dcount(ManagedDeviceId)\n);\nlet DevicesCompliance = toscalar(\n    IntuneDeviceComplianceOrg\n    | where isnotnull(LatestAssignmentTime)\n    | where TimeGenerated between (LatestAssignmentTime .. LatestAssignmentTime + 24h)\n    | where OperationName == 'DeviceCompliance'\n    | where isnotempty(DeviceId)\n    | summarize dcount(DeviceId)\n);\nprint CompliancePercentage = iff(coalesce(DevicesSynced, 0) == 0, 0.0, round((todouble(coalesce(DevicesCompliance, 0)) * 100.0) / todouble(DevicesSynced), 2))",
              "size": 9,
              "title": "FW Policy Follow-up %",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "showBorder": true,
                "leftContent": {
                  "columnMatch": "CompliancePercentage",
                  "formatter": 12,
                  "formatOptions": {
                    "palette": "greenRed",
                    "showIcon": true
                  }
                }
              }
            },
            "customWidth": "40"
          },
          {
            "type": 3,
            "name": "intunefw-trend",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let FWPolicyName = 'FW Policy';\nlet StartDay = toscalar(IntuneAuditLogs | where TimeGenerated {TimeRange} | summarize startofday(min(TimeGenerated)));\nlet EndDay = toscalar(IntuneAuditLogs | where TimeGenerated {TimeRange} | summarize startofday(max(TimeGenerated)));\nlet DailyActivity = IntuneAuditLogs\n| where TimeGenerated {TimeRange}\n| extend P = parse_json(Properties)\n| extend PolicyName = tostring(coalesce(P.TargetDisplayNames[0], P.Targets[0].Name, ''))\n| where PolicyName =~ FWPolicyName\n| extend OperationCategory = case(OperationName has 'Assignment', 'Assignment', OperationName has 'Create', 'Create', OperationName has 'Patch', 'Update', 'Other')\n| summarize Create = countif(OperationCategory == 'Create'), Assignment = countif(OperationCategory == 'Assignment'), Update = countif(OperationCategory == 'Update') by Day = bin(TimeGenerated, 1d);\nrange Day from iif(isnull(StartDay), startofday(ago(30d)), StartDay) to iif(isnull(EndDay), startofday(now()), EndDay) step 1d\n| join kind=leftouter DailyActivity on Day\n| project Timestamp = Day, Create = coalesce(Create, 0), Assignment = coalesce(Assignment, 0), Update = coalesce(Update, 0)\n| order by Timestamp asc",
              "size": 4,
              "title": "FW Policy Activity Trend",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "linechart",
              "chartSettings": {
                "showLegend": true,
                "seriesLabelSettings": [
                  {
                    "seriesName": "Create",
                    "color": "green"
                  },
                  {
                    "seriesName": "Assignment",
                    "color": "blue"
                  },
                  {
                    "seriesName": "Update",
                    "color": "red"
                  }
                ]
              }
            },
            "customWidth": "100"
          },
          {
            "type": 3,
            "name": "intunefw-grid",
            "content": {
              "version": "KqlItem/1.0",
              "query": "let FWPolicyName = 'FW Policy';\nlet PolicyOps = IntuneAuditLogs\n| where TimeGenerated {TimeRange}\n| where OperationName has 'DeviceManagementConfigurationPolicy'\n| extend P = parse_json(Properties)\n| extend PolicyName = tostring(coalesce(P.TargetDisplayNames[0], P.Targets[0].Name, '<unknown-policy>'))\n| where PolicyName =~ FWPolicyName\n| extend PolicyObjectId = tostring(P.TargetObjectIds[0])\n| extend AssignmentObjectId = tostring(P.TargetObjectIds[1])\n| extend AssignmentGroupId = tostring(extract('\\\"Name\\\":\\\"Target.GroupId\\\",\\\"Old\\\":.*?\\\"New\\\":\\\"([^\\\"]+)\\\"', 1, Properties))\n| extend Platforms = tostring(extract('\\\"Name\\\":\\\"Platforms\\\",\\\"Old\\\":.*?\\\"New\\\":\\\"([^\\\"]*)\\\"', 1, Properties))\n| extend SettingCount = toint(extract('\\\"Name\\\":\\\"SettingCount\\\",\\\"Old\\\":.*?\\\"New\\\":\\\"([^\\\"]+)\\\"', 1, Properties))\n| extend ApiVersion = tostring(extract('\\\"Name\\\":\\\"DeviceManagementAPIVersion\\\",\\\"Old\\\":.*?\\\"New\\\":\\\"([^\\\"]+)\\\"', 1, Properties))\n| extend AuditEventId = tostring(P.AuditEventId)\n| extend OperationCategory = case(OperationName has 'Assignment', 'Assignment', OperationName has 'Create', 'Create', OperationName has 'Patch', 'Update', 'Other')\n| project TimeGenerated, PolicyName, OperationCategory, OperationName, ResultType, Identity, PolicyObjectId, AssignmentObjectId, AssignmentGroupId, Platforms, SettingCount, ApiVersion, AuditEventId, ResultDescription;\nlet DeviceSync = IntuneAuditLogs\n| where TimeGenerated {TimeRange}\n| where OperationName == 'syncDevice ManagedDevice'\n| extend ManagedDeviceId = tostring(extractjson('$.TargetObjectIds[0]', Properties))\n| where isnotempty(ManagedDeviceId)\n| project SyncTime = TimeGenerated, ManagedDeviceId;\nlet Compliance = IntuneDeviceComplianceOrg\n| where TimeGenerated {TimeRange}\n| where OperationName == 'DeviceCompliance'\n| where isnotempty(DeviceId)\n| project ComplianceTime = TimeGenerated, DeviceId;\nPolicyOps\n| extend JoinKey = 1\n| join kind=leftouter (DeviceSync | extend JoinKey = 1) on JoinKey\n| summarize DevicesSyncedIn24h = dcountif(ManagedDeviceId, SyncTime between (TimeGenerated .. TimeGenerated + 24h)) by TimeGenerated, PolicyName, OperationCategory, OperationName, ResultType, Identity, PolicyObjectId, AssignmentObjectId, AssignmentGroupId, Platforms, SettingCount, ApiVersion, AuditEventId, ResultDescription\n| extend JoinKey = 1\n| join kind=leftouter (Compliance | extend JoinKey = 1) on JoinKey\n| summarize DevicesWithComplianceCheckIn24h = dcountif(DeviceId, ComplianceTime between (TimeGenerated .. TimeGenerated + 24h)), DevicesSyncedIn24h = any(DevicesSyncedIn24h) by TimeGenerated, PolicyName, OperationCategory, OperationName, ResultType, Identity, PolicyObjectId, AssignmentObjectId, AssignmentGroupId, Platforms, SettingCount, ApiVersion, AuditEventId, ResultDescription\n| extend DeliveryEvidence = case(OperationCategory != 'Assignment', 'N/A (not assignment)', DevicesSyncedIn24h > 0 and DevicesWithComplianceCheckIn24h > 0, 'Likely delivered (sync + compliance activity observed)', DevicesSyncedIn24h > 0, 'Partial evidence (sync observed)', 'No post-assignment signal in 24h window')\n| project ['Last Update'] = TimeGenerated, ['Policy Name'] = PolicyName, ['Operation Category'] = OperationCategory, ['Result'] = ResultType, ['Changed By'] = Identity, ['Assignment Group ID'] = AssignmentGroupId, ['Devices Synced (24h)'] = DevicesSyncedIn24h, ['Devices Compliance Check (24h)'] = DevicesWithComplianceCheckIn24h, ['Delivery Evidence'] = DeliveryEvidence\n| order by ['Last Update'] desc",
              "size": 2,
              "title": "FW Policy Detail",
              "timeContextFromParameter": "TimeRange",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "showExportToExcel": true,
              "exportToExcelOptions": "visible",
              "gridSettings": {
                "filter": true,
                "rowLimit": 10000,
                "formatters": [
                  {
                    "columnMatch": "Result",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "icons",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Success", "representation": "success", "text": "{0}{1}" },
                        { "operator": "==", "thresholdValue": "Failure", "representation": "2", "text": "{0}{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "3", "text": "{0}{1}" }
                      ]
                    }
                  },
                  {
                    "columnMatch": "Operation Category",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Create", "representation": "green", "text": "{0}{1}" },
                        { "operator": "==", "thresholdValue": "Update", "representation": "orange", "text": "{0}{1}" },
                        { "operator": "==", "thresholdValue": "Assignment", "representation": "blue", "text": "{0}{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "yellow", "text": "{0}{1}" }
                      ]
                    }
                  },
                  {
                    "columnMatch": "Delivery Evidence",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Likely delivered (sync + compliance activity observed)", "representation": "green", "text": "{0}{1}" },
                        { "operator": "==", "thresholdValue": "Partial evidence (sync observed)", "representation": "blue", "text": "{0}{1}" },
                        { "operator": "==", "thresholdValue": "No post-assignment signal in 24h window", "representation": "red", "text": "{0}{1}" },
                        { "operator": "Default", "thresholdValue": null, "representation": "yellow", "text": "{0}{1}" }
                      ]
                    }
                  }
                ]
              }
            },
            "customWidth": "100"
          }
        ]
      }
    }

